def longest_path:
  if not matrix:
    return 0
  m, n = len(matrix), len(matrix[0])
  dp = [[0] * n for _ in range(m)]
  def depth_first_search(i, j):
    if dp[i][j]:
      return dp[i][j]
    val = matrix[i][j]
    best = 1
    for x, y in [(-1,0), (1,0), (0,1), (0,-1)]:
      nx, ny = i+x, j+y
      if 0 <= nx < m and 0 <= ny < n and matrix[nx][ny] > val:
        best = max(best, 1 + depth_first_search(nx, ny))
    dp[i][j] = best
    return best
return max(depth_first_search(i, j) for i in range(m) for j in range(n))

def tallest_billboard(rods):
  dp = {0:0}
  for i in rods:
    curr = dp.copy()
    for diff, height in curr.items():
      dp[diff+i]=max[dp.get(diff+i,0),height]
      new_diff = abs(diff - i)
      dp[new_diff] = max(dp.get(new_diff, 0), height + min(diff, i))
  return dp[0]

